INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Selections management$q$, $q$Lets homeowners choose finishes and fixtures within a defined budget, tracking allowances and overages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Change order workflow$q$, $q$Structured process for proposing, approving, and billing changes to the original contract scope.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Client portal$q$, $q$Gives homeowners a single place to see schedules, photos, selections, and communication history.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Scheduling$q$, $q$Job-site scheduling tools for coordinating subcontractors and internal teams across multiple active projects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Budgeting and job costing$q$, $q$Tracks estimated versus actual costs per project to help builders protect margins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Accounting integrations$q$, $q$Syncs with QuickBooks and Xero to keep project financials aligned with company books.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Mobile access$q$, $q$Mobile apps let site managers update schedules, log photos, and communicate from the job site.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Purpose-built for the custom home and remodeling workflow, including selections and change orders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Strong client communication tools that reduce phone and email back-and-forth with homeowners$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Established integrations with common accounting software$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Large existing user base with over 100,000 building professionals historically on the platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$No longer actively developed as an independent product; the company is directing customers to Buildertrend$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$New projects cannot be created in CoConstruct after March 31, 2027$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Not a realistic option for evaluating new software today given its planned sunset$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Support and updates have reportedly slowed since the Buildertrend acquisition$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Is CoConstruct still available for new customers?$q$, $q$CoConstruct is not being actively promoted to new customers; Buildertrend, which acquired CoConstruct in 2021, is now the primary product being sold, with CoConstruct customers being migrated over on a phased timeline.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$What happens to my existing CoConstruct data?$q$, $q$According to CoConstruct's own migration guidance, historical project data remains accessible indefinitely even after a customer moves to Buildertrend.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Until when can I create new projects in CoConstruct?$q$, $q$CoConstruct's migration page states that new projects can still be added through March 31, 2027, after which new projects must be created directly in Buildertrend.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$What is the relationship between CoConstruct and Buildertrend?$q$, $q$Buildertrend acquired CoConstruct in February 2021. The two were run as separate products for several years, but they are now merging into a single Buildertrend platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$What did CoConstruct cost?$q$, $q$Historical pricing was tiered by active job sites with client access, commonly cited around $199 to $599 per month depending on team size and features, though CoConstruct is no longer the primary product being sold to new buyers.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Custom home builder managing client selections$q$, $q$A builder running several custom homes at once uses selections management and the client portal to keep homeowners informed about finish choices and budget impact.$q$, $q$Custom home builders (5-50 homes/year)$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Remodeling contractor tracking change orders$q$, $q$A remodeling firm uses the change order workflow to document scope changes and get client sign-off before billing for extra work.$q$, $q$Remodeling and renovation contractors$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Core$q$, $q$$199/month$q$, $q$Monthly (annual billing discount available)$q$, NULL, $q$["2 users","Client and subcontractor communication","Basic scheduling","Selections management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Essential$q$, $q$$399/month$q$, $q$Monthly (annual billing discount available)$q$, NULL, $q$["5 users","Budgeting and change orders","QuickBooks/Xero integration","Client portal"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$Advanced$q$, $q$$599/month$q$, $q$Monthly (annual billing discount available)$q$, NULL, $q$["Unlimited users","Advanced reporting","Full financial tools","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CoConstruct is a construction project management platform launched in 2005 in Charlottesville, Virginia, built specifically for custom home builders and remodeling contractors managing a handful of active projects at a time rather than large commercial sites.$q$, $q$In February 2021, competitor Buildertrend acquired CoConstruct, and the two companies have since been merging their platforms. As of 2026, CoConstruct is in an active wind-down: existing customers can continue using it and their historical data remains accessible, but new projects can only be started in CoConstruct through March 31, 2027, after which all new work moves to Buildertrend.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CoConstruct's core toolset was built around the custom-build client experience: selections management for choosing finishes within budget, change order workflows, scheduling, and a client portal that keeps homeowners updated without constant phone calls.$q$, $q$On the operations side, it offered budgeting and job costing, subcontractor and vendor communication, photo and document storage for job sites, and accounting sync with QuickBooks and Xero, along with mobile access for site managers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CoConstruct historically sold three tiers priced by active job sites with client access rather than flat per-seat pricing: a Core tier around $199/month for small teams, an Essential tier around $399/month, and an unlimited-user Advanced tier around $599/month, with a discount for annual billing.$q$, $q$Because CoConstruct is being folded into Buildertrend, these legacy prices are not being offered to new customers; prospective buyers are directed to Buildertrend's own pricing and plans instead.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eb149729-5f83-425f-8d50-05c96971bdf3', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Docs with embedded tables$q$, $q$Combine free-form text with structured, relational, spreadsheet-like tables in a single document.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Packs integrations$q$, $q$Connect to third-party tools (Slack, Jira, Google Calendar, and more) to pull in or act on external data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Buttons and automations$q$, $q$Add clickable actions and scheduled automations that update rows, send notifications, or trigger workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Cross-doc tables$q$, $q$Reference and sync tables across multiple docs, available on Pro and above plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$AI in documents$q$, $q$Built-in AI assistance for writing, summarizing, and working with table data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Doc Maker billing model$q$, $q$Only users who create/manage docs are billed; users who only edit existing content are free.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Cross-platform apps$q$, $q$Native apps for web, Mac, Windows, iOS, and Android keep docs accessible across devices.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Flexible enough to replace multiple point tools (docs, spreadsheets, light project management) with one workspace$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Doc Maker billing model can be cost-effective for teams with many read-only collaborators$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Strong integration ecosystem via Packs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Existing docs and automations were preserved through the Grammarly acquisition and Superhuman Docs rebrand$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Recent rebrand to Superhuman Docs can create confusion when researching the product under its old "Coda" name$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Per-Doc-Maker pricing can get expensive for organizations with many document creators$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Advanced automation and cross-doc features are gated behind paid plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Feature depth in any single area (docs, tables, automations) is generally less specialized than dedicated tools in that category$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Is Coda still called Coda?$q$, $q$No. As of July 8, 2026, Coda was renamed Superhuman Docs as part of Grammarly's broader rebrand of its parent company to Superhuman. It is the same underlying product.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$What happens to my existing Coda docs after the rebrand?$q$, $q$According to Superhuman's help documentation, existing docs, workflows, tables, Packs, automations, and formulas continue to work exactly as before under the new Superhuman Docs name.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Who owns Coda/Superhuman Docs now?$q$, $q$Grammarly acquired Coda in December 2024. Grammarly itself rebranded to Superhuman in October 2025, and Coda's co-founder Shishir Mehrotra became CEO of the combined company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$How much does Superhuman Docs (Coda) cost?$q$, $q$It has a free tier plus paid Pro ($12/Doc Maker/month) and Team ($36/Doc Maker/month) plans, with custom Enterprise pricing; only document creators, not editors, are billed.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Is there a mobile app?$q$, $q$Yes, native apps are available for iOS and Android in addition to web, Mac, and Windows apps.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Internal team wiki with live data$q$, $q$Teams build an internal knowledge base where policy docs sit alongside live, filterable tables of projects, contacts, or assets.$q$, $q$Operations and internal knowledge teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Lightweight product/project tracker$q$, $q$Product teams replace a mix of spreadsheets and task tools with a single doc containing a roadmap table, status buttons, and automations.$q$, $q$Product managers and small cross-functional teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to ~50 objects and 1,000 rows per doc","Basic collaboration","Limited automations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Pro$q$, $q$$12/Doc Maker/month ($10/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Cross-doc tables","Automations","Additional AI credits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Team$q$, $q$$36/Doc Maker/month ($30/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Admin controls","Advanced permissions","Higher AI credit allowance"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["SSO/SCIM","1-year audit log retention","SOC 2 Type II, ISO 27001/27017/27018","12,000+ monthly AI credits per Doc Maker"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Coda launched in 2014 as an all-in-one document and database workspace, letting teams combine free-form writing with structured, relational tables and app-like automations in a single doc. Grammarly acquired Coda in December 2024, and in October 2025 Grammarly rebranded its whole company to Superhuman, bringing Coda into a unified product suite alongside Grammarly's writing assistant and the Superhuman email client.$q$, $q$On July 8, 2026, Coda itself was renamed Superhuman Docs. Existing docs, tables, Packs, automations, and formulas continue to work as before; the change is primarily branding plus new AI features and backend infrastructure, not a product replacement.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of the product is its blend of free-form documents and structured tables: teams can write a project brief and embed a live, filterable database of tasks, contacts, or inventory in the same page, with changes reflected everywhere the data is referenced.$q$, $q$Packs (third-party integrations), buttons, and automations let a doc trigger actions like sending a Slack message, updating a calendar event, or pulling data from another tool, turning documents into lightweight internal applications. AI features are built directly into the writing and table-editing experience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pricing runs Free, Pro at $12 per Doc Maker per month ($10 billed annually), Team at $36 per Doc Maker per month ($30 billed annually), and custom-priced Enterprise. Only people who create or manage docs ("Doc Makers") are billed; collaborators who just edit content are free.$q$, $q$Enterprise adds SSO/SCIM, extended audit log retention, SOC 2 Type II and ISO 27001/27017/27018 compliance, dedicated support, and a larger monthly AI credit allowance per Doc Maker.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
