INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('68d2cc39-83c1-4877-8a8c-2057a904b538', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$AI autocomplete$q$, $q$Single- and multi-line code completions across 70+ programming languages in supported editors.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$In-editor chat$q$, $q$Ask questions about the codebase or generate code directly inside the editor.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Devin Local (formerly Cascade)$q$, $q$Built-in agentic mode that can plan and execute multi-file code changes and run commands, rewritten in Rust for efficiency.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Agent Command Center$q$, $q$Kanban-style dashboard for tracking and managing multiple local and cloud coding agents at once.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Agent Client Protocol (ACP) support$q$, $q$Open protocol allowing third-party agents like Codex, Claude Agent, and Gemini CLI to run inside the editor.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Editor plugins$q$, $q$Plugins for VS Code, JetBrains IDEs, Neovim, and Visual Studio for developers who prefer their existing editor.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Spaces$q$, $q$Groups sessions, PRs, files, and Git worktrees so multiple agents can share context on related work.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Generous free tier with unlimited basic autocomplete and support for 70+ languages$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Backward-compatible rebrand meant existing Windsurf/Codeium users kept accounts, plans, and settings automatically$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Open Agent Client Protocol support avoids locking users into a single vendor's agent$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Backed by Cognition AI's broader Devin agent ecosystem and ongoing investment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Two rebrands in under two years (Codeium to Windsurf to Devin Desktop) make the product harder to track and compare across reviews$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Cascade, the previous built-in agent, was fully retired on July 1, 2026, requiring users to adapt to Devin Local$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Pro plan pricing has increased over time (from $15 to $20/month as of mid-2026)$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Full agentic feature set requires the standalone desktop app rather than the lightweight plugin$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Is Codeium still called Codeium?$q$, $q$No. Codeium became Windsurf in late 2024, and Windsurf was rebranded to Devin Desktop by Cognition AI on June 2, 2026. Codeium now refers to the underlying authentication and backend technology.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Do I need to reinstall anything after the rebrand?$q$, $q$No. Cognition shipped Devin Desktop as an over-the-air update to existing Windsurf installs, carrying over accounts, plans, extensions, keybindings, and MCP connections.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$What happened to Cascade?$q$, $q$Cascade, Windsurf's original built-in agent, reached end of life on July 1, 2026, and was replaced by Devin Local, a Rust-based agent reported to be roughly 30% more token-efficient.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Did pricing change with the rebrand?$q$, $q$No. Cognition's documentation states pricing is unchanged through the rebrand, including for legacy Windsurf Enterprise plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Who owns this product now?$q$, $q$Cognition AI, the developer of the Devin autonomous coding agent, acquired Windsurf in December 2025 for a reported price of about $250 million.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Agent-assisted feature development$q$, $q$A developer describes a feature in natural language and Devin Local plans and implements multi-file changes with the developer reviewing each step.$q$, $q$Software engineers and development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Lightweight autocomplete in an existing editor$q$, $q$A developer who prefers VS Code or a JetBrains IDE installs the plugin for free AI autocomplete and chat without switching editors.$q$, $q$Individual developers$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Unlimited basic autocomplete","In-editor chat","Limited agent usage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Pro$q$, $q$$20/month$q$, $q$Monthly$q$, NULL, $q$["Expanded agent usage credits","Priority model access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Max$q$, $q$$200/month$q$, $q$Monthly$q$, NULL, $q$["Highest usage quotas","Built for power users"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Teams$q$, $q$$80/month + $40/seat$q$, $q$Monthly$q$, NULL, $q$["Team seat management","Shared usage credits","Admin controls"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Legacy Windsurf Enterprise plans honored","Dedicated support","Custom security controls"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$This AI coding tool has changed names twice since its 2021 founding as Exafunction. It became Codeium in 2022 as an AI autocomplete plugin, then Windsurf in late 2024 as a full standalone AI-native code editor built around an agentic mode called Cascade.$q$, $q$In December 2025, Cognition AI (maker of the Devin coding agent) acquired Windsurf, and on June 2, 2026 rebranded it to Devin Desktop. The rebrand was delivered as an update to existing installs, preserving accounts, plans, and configuration, with Devin Local replacing Cascade as the built-in agent.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The product combines traditional AI autocomplete and in-editor chat with agentic task execution: an agent can read a codebase, plan multi-step changes, edit multiple files, and run commands with developer oversight.$q$, $q$The Agent Command Center presents a Kanban-style view of local and cloud agents, and the editor supports the Agent Client Protocol (ACP), letting outside agents such as Codex, Claude Agent, and Gemini CLI run inside the same interface. Editor plugins remain available for VS Code, JetBrains IDEs, and other environments for developers who don't want the full standalone app.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free plan offers unlimited basic autocomplete, in-editor chat, and limited agent usage across 70+ programming languages with no credit card required. Paid tiers are Pro at $20/month, Max at $200/month, and Teams at $80/month plus $40 per seat.$q$, $q$Enterprise pricing is custom and, per Cognition's documentation, legacy Windsurf Enterprise contracts continue to be honored under the Devin Desktop name.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa297366-5cbc-4dc6-bc99-46ced5726132', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Phone-verified mobile data$q$, $q$Diamond Data uses human researchers to manually confirm mobile numbers rather than algorithmic prediction alone.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Verified email data$q$, $q$Contact-level email data intended to reduce bounce rates in outbound campaigns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$EMEA-focused coverage$q$, $q$Strong data coverage across UK, DACH, Benelux, Nordics, France, and Spain relative to US-centric providers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$CRM and sales engagement integrations$q$, $q$Native connectors for Salesforce, HubSpot, Outreach, Salesloft, Microsoft Dynamics 365, Bullhorn, and Pipedrive.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Chrome extension / LinkedIn prospecting$q$, $q$Surfaces verified contact details while browsing LinkedIn Sales Navigator or a company's website.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Compliance tooling$q$, $q$GDPR/CCPA compliance, Do Not Call and TPS list scrubbing across roughly 15 territories, ISO 27001 and SOC 2 Type II certification.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Intent and firmographic data$q$, $q$Company-level data and buying signals layered on top of contact records for account prioritization.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Strong reputation for data accuracy in European and EMEA markets specifically$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Human-verified mobile numbers rather than purely predictive/algorithmic data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Heavy emphasis on GDPR/CCPA compliance and Do Not Call list scrubbing, reducing legal risk for outbound teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Broad CRM and sales engagement integrations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$No public pricing; requires a sales conversation and negotiation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Reported contract costs can be significant, with platform fees alone often in the $15,000-$25,000/year range$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$US data coverage is generally considered less comprehensive than EMEA coverage$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Primarily designed for outbound sales teams rather than broader marketing or research use cases$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$How much does Cognism cost?$q$, $q$Cognism does not publish pricing. Third-party sources tracking real deals report typical annual contracts ranging from roughly $1,500 to $25,000 depending on tier, seat count, and negotiation; buyers must request a quote directly from Cognism.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Is Cognism GDPR compliant?$q$, $q$Yes. Cognism markets GDPR and CCPA compliance as a core part of its product, including notifying contacts of database inclusion within GDPR timeframes and regular scrubbing against Do Not Call lists.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$What CRMs does Cognism integrate with?$q$, $q$Cognism has native integrations with Salesforce, HubSpot, Outreach, Salesloft, Microsoft Dynamics 365, Bullhorn, and Pipedrive.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$How is Cognism's phone data verified?$q$, $q$Its Diamond Data tier relies on human researchers who call and manually confirm mobile numbers rather than relying purely on algorithmic prediction, with a reported accuracy around 87%.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Who founded Cognism?$q$, $q$Cognism was founded by James Isilay (CEO) and Stjepan Buljat (CTO) in 2015, and is headquartered in London.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$Outbound SDR prospecting$q$, $q$Sales development reps use Cognism to build verified contact lists for cold calling and cold email campaigns, especially into European accounts.$q$, $q$SDR and BDR teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$European GTM expansion$q$, $q$A US-based company expanding into EMEA uses Cognism for compliant, region-specific contact data that meets GDPR requirements.$q$, $q$RevOps and sales leadership expanding into Europe$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cognism is a B2B sales intelligence platform founded in 2015 by James Isilay and Stjepan Buljat and headquartered in London, with additional offices in New York, Skopje, and Zadar. It provides verified contact and company data to power outbound prospecting, with a particular strength in coverage across EMEA markets.$q$, $q$The company built its reputation on human-verified mobile phone data and strict regulatory compliance, positioning itself against US-centric providers like ZoomInfo for teams that need GDPR- and CCPA-compliant data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cognism's Diamond Data uses human researchers to manually verify mobile numbers rather than relying solely on algorithmic prediction, and the platform maintains over 10 million phone-verified contacts globally alongside firmographic and intent data.$q$, $q$It integrates natively with Salesforce, HubSpot, Outreach, Salesloft, Microsoft Dynamics 365, Bullhorn, and Pipedrive, and offers a Chrome extension for pulling verified contact data while browsing LinkedIn or company websites.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cognism does not publish pricing publicly; buyers go through a demo and sales negotiation to get a quote. Third-party deal-tracking sources report typical real-world contracts ranging from around $1,500 to $25,000 per year depending on tier, seat count, and negotiation.$q$, $q$These figures are not confirmed by Cognism's own materials and should be treated as estimates; prospective buyers should request a current quote directly from Cognism.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Drag-and-drop form builder$q$, $q$No-code interface for building custom forms with a wide range of field types and layouts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Conditional logic$q$, $q$Show, hide, or require fields dynamically based on a respondent's previous answers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Payment collection$q$, $q$Accept credit card payments directly through forms via Stripe, PayPal, or Square.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Electronic signatures$q$, $q$Capture legally usable e-signatures as part of a form submission on Pro and higher plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Workflow and approvals$q$, $q$Route submissions through approval steps and a client portal on the Team plan and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$HIPAA-compliant configuration$q$, $q$Enterprise plan supports HIPAA-compliant data handling for healthcare-related forms.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Integrations via Zapier and webhooks$q$, $q$Connect form submissions to other software using Zapier, Microsoft Power Automate, or JSON webhooks.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Genuinely usable free plan with unlimited forms and payment acceptance, not just a trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Conditional logic and calculations rival more expensive form tools without requiring code$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Built-in payment processing simplifies registration and order forms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$HIPAA-compliant configuration available for healthcare and sensitive-data use cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Entry volume and storage limits scale with price, which can force upgrades for growing organizations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Higher-end collaboration features (client portal, approvals, SSO) are locked to Team and Enterprise tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Guest user allowances are capped even on paid plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Smaller integration ecosystem compared to larger form/survey platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Does Cognito Forms have a free plan?$q$, $q$Yes. The Individual plan is free with no credit card required, offering unlimited forms, up to 100 entries per month, 100 MB of storage, and payment acceptance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Can Cognito Forms accept payments?$q$, $q$Yes, forms can accept credit card payments through Stripe, PayPal, or Square on any plan, including the free tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$How much does Cognito Forms cost?$q$, $q$Paid plans range from about $19.20/month (Pro, billed annually) to $129.60/month (Enterprise, billed annually), with monthly billing priced somewhat higher on each tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Is Cognito Forms HIPAA compliant?$q$, $q$HIPAA-compliant configuration is available on the Enterprise plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$What integrations does Cognito Forms support?$q$, $q$It integrates with other software via Zapier, Microsoft Power Automate, and JSON webhooks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Who founded Cognito Forms?$q$, $q$Cognito Forms was founded in 2013 by Alain Meier and Jamie Thomas in Columbia, South Carolina.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Event registration with payment$q$, $q$An organization builds a registration form with conditional pricing logic and collects payment directly through the form.$q$, $q$Nonprofits and event organizers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Healthcare intake forms$q$, $q$A clinic uses HIPAA-compliant form configuration to collect patient intake information securely.$q$, $q$Healthcare providers and clinics$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Individual$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["1 user","100 entries/month","100 MB storage","Unlimited forms","Payment acceptance"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Pro$q$, $q$$24/month ($19.20/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["2 users","2,000 entries/month","1 GB storage","Electronic signatures","Remove branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Team$q$, $q$$49/month ($39.20/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["5 users + 5 guests","10,000 entries/month","10 GB storage","Client portal","Workflow & approvals"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$Enterprise$q$, $q$$174/month ($129.60/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["20 users + 20 guests","Unlimited entries","100 GB storage","HIPAA compliance","Single sign-on"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cognito Forms is a no-code online form builder founded in 2013 by Alain Meier and Jamie Thomas in Columbia, South Carolina. It grew out of the founders' custom web development work and was built to let non-developers create sophisticated forms with logic, calculations, and payment collection.$q$, $q$The platform serves small businesses, nonprofits, schools, and healthcare organizations that need forms more capable than basic contact forms but without the cost or complexity of building custom software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Forms support conditional logic, automatic cost calculations, date comparisons, electronic signatures, and file uploads, all configured through a drag-and-drop builder without code.$q$, $q$Built-in payment acceptance through Stripe, PayPal, or Square lets organizations collect money directly through registration, order, or application forms, while Zapier, Microsoft Power Automate, and webhook support connect form data to other business systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cognito Forms offers a free-forever Individual plan (1 user, 100 entries/month, 100 MB storage) alongside three paid tiers: Pro at $19.20-$24/month, Team at $39.20-$49/month, and Enterprise at $129.60-$174/month, with the lower figure reflecting annual billing.$q$, $q$Higher tiers raise entry and storage limits and add capabilities like electronic signatures, a client portal, workflow approvals, HIPAA compliance, and single sign-on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0cb449-bb08-4c54-9e30-c13e9e4fee0c', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Real-time chat$q$, $q$Slack-style instant messaging channels within a workspace.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Rich-text pages$q$, $q$Notion-style documents and wikis with nested pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Customizable databases$q$, $q$Structured data with table, kanban, and calendar views similar to Notion databases.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$File management$q$, $q$Store and share files within secure workspaces alongside chat and pages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Local-first sync$q$, $q$Local SQLite storage with background sync keeps the app usable offline and fast to read.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$CRDT-based collaboration$q$, $q$Yjs-powered conflict-free real-time editing lets multiple users edit the same content simultaneously.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Self-hosting$q$, $q$Full self-hosted deployment using PostgreSQL, Redis/Valkey, and a choice of storage backends.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Fully open source (Apache 2.0) with an active GitHub community and frequent releases$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Local-first design keeps the app fast and usable offline$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Combines chat, docs, databases, and files in one tool instead of several separate apps$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Free to self-host with no per-seat licensing cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Young project (created 2024) without the maturity or ecosystem of established tools like Notion or Slack$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Cloud hosting is still in beta with no finalized pricing, so long-term cost is uncertain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Self-hosting requires managing PostgreSQL, Redis/Valkey, and storage infrastructure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Smaller integration and plugin ecosystem compared to mature commercial alternatives$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Is Colanode free?$q$, $q$Yes, Colanode is open source (Apache 2.0) and free to self-host. Its hosted cloud option is also currently free while in beta.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Can Colanode be self-hosted?$q$, $q$Yes. Self-hosting requires PostgreSQL with the pgvector extension, Redis or Valkey, and a storage backend such as the local filesystem, S3-compatible storage, Google Cloud Storage, or Azure Blob Storage.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$What does Colanode replace?$q$, $q$It's positioned as a combined alternative to Slack (chat) and Notion (pages, wikis, and databases) in a single self-hostable application.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Does Colanode work offline?$q$, $q$Yes. Its local-first architecture saves changes to a local SQLite database first and syncs to the server in the background, so it remains usable offline.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$What license is Colanode released under?$q$, $q$Colanode is released under the Apache 2.0 open-source license.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Privacy-conscious team collaboration$q$, $q$A team that wants full control over its data self-hosts Colanode to get Slack-and-Notion-style functionality without relying on third-party SaaS storage.$q$, $q$Privacy-focused teams and technical organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$Offline-capable team workspace$q$, $q$A distributed or field team relies on Colanode's local-first sync to keep working on chat, pages, and files even without a stable internet connection.$q$, $q$Remote and distributed teams$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Colanode is an open-source, local-first collaboration workspace created in mid-2024 that combines Slack-style chat with Notion-style pages, databases, and file storage in one self-hostable application. It is released under the Apache 2.0 license and has grown to over 5,000 GitHub stars.$q$, $q$Its local-first architecture writes changes to a local SQLite database first and syncs to the server in the background, so the app remains usable offline and reads happen instantly from the local device.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform bundles real-time chat, rich-text pages/wikis, customizable databases with table, kanban, and calendar views, and file management in a single workspace. Real-time collaborative editing is powered by CRDTs via the Yjs library, allowing multiple people to edit the same content simultaneously without conflicts.$q$, $q$It's available as a web app, a desktop app built with Electron, and a self-hosted server. Self-hosting requires PostgreSQL with pgvector, Redis or Valkey, and a storage backend (local filesystem, S3-compatible, Google Cloud Storage, or Azure Blob Storage).$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Colanode itself is free and open source with no license fee to self-host. The company also offers hosted Colanode Cloud servers in the EU and US, currently in a free public beta while a long-term monetization approach is finalized.$q$, $q$As of mid-2026 there is no published paid pricing tier; teams that want guaranteed pricing or support should plan around self-hosting rather than assuming the current free cloud beta will remain free indefinitely.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3c831cf1-d2a5-44c9-9cea-c5206afcba70', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Real-time collaborative editing$q$, $q$Multiple users can edit the same document, spreadsheet, or presentation simultaneously in a browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Writer, Calc, Impress, Draw$q$, $q$Full office suite covering word processing, spreadsheets, presentations, and vector graphics.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$OpenDocument and Microsoft Office compatibility$q$, $q$Native support for ODF plus strong compatibility with .docx, .xlsx, and .pptx files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Self-hosted deployment$q$, $q$Runs on an organization's own infrastructure integrated with Nextcloud, ownCloud, EGroupware, or Pydio.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Native offline apps$q$, $q$Dedicated apps for Android, ChromeOS, iOS, iPadOS, Linux, macOS, and Windows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$CODE free edition$q$, $q$No-cost development edition suitable for testing, personal use, and small teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$GDPR-friendly data residency$q$, $q$Self-hosting keeps documents within an organization's own infrastructure rather than third-party cloud servers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Fully self-hostable, giving organizations complete control over document data and residency$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Free CODE edition available for testing or small-scale personal use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Strong file format compatibility with both OpenDocument and Microsoft Office formats$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Can be more cost-effective than per-user SaaS office suites at scale for organizations that can run their own infrastructure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Requires an existing platform like Nextcloud or ownCloud plus infrastructure to self-host; it isn't a simple standalone signup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Free CODE edition is explicitly not recommended for large-scale production use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Commercial support and stable enterprise editions require a paid subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Feature parity with Microsoft 365's most advanced collaboration and AI features is not guaranteed$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Is Collabora Online free?$q$, $q$The Collabora Online Development Edition (CODE) is free, suited to testing, personal use, or small teams. Production-grade, commercially supported editions require a paid subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Can Collabora Online be used without Nextcloud?$q$, $q$It requires an underlying file-storage and user-management platform such as Nextcloud, ownCloud, EGroupware, or Pydio; it does not run as a fully standalone product.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Does Collabora Online support Microsoft Office file formats?$q$, $q$Yes, it offers strong compatibility with Microsoft Office formats such as .docx, .xlsx, and .pptx, alongside native OpenDocument support.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$How much does Collabora Online cost for businesses?$q$, $q$Commercial pricing has been reported starting around €3 per user per month for on-premise deployments up to about 99 users, billed annually, with custom pricing for larger Enterprise deployments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Who develops Collabora Online?$q$, $q$It's developed by Collabora, a UK-based open-source consulting company founded in 2005 and headquartered in Cambridge, which is also one of the largest contributors to the LibreOffice codebase.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Self-hosted office suite for a Nextcloud deployment$q$, $q$An organization already running Nextcloud adds Collabora Online (CODE or a paid edition) to get in-browser document editing without sending files to a third-party cloud.$q$, $q$IT teams and privacy-focused organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Public sector document collaboration$q$, $q$A government agency with data-residency requirements self-hosts Collabora Online to keep collaborative document editing entirely on infrastructure it controls.$q$, $q$Public sector and regulated organizations$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$CODE (Collabora Online Development Edition)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted","Community support only","Not recommended for large-scale production"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Business$q$, $q$From approximately €3/user/month (on-premise, up to 99 users)$q$, $q$Annual$q$, NULL, $q$["Commercial support","Signed security updates","Production-grade stability"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$Enterprise$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["Large-scale deployment","SLA-backed support","Custom integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Collabora Online is a browser-based collaborative office suite built on LibreOffice technology, developed by Collabora, an open-source consulting company founded in 2005 and headquartered in Cambridge, UK. It's positioned as a self-hostable, open-source alternative to Google Workspace and Microsoft 365.$q$, $q$Rather than running as a standalone cloud service, Collabora Online plugs into an existing file-storage platform such as Nextcloud, ownCloud, EGroupware, or Pydio, which handles storage and user accounts while Collabora provides the in-browser editing engine for Writer, Calc, Impress, and Draw documents.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$It enables real-time, multi-user collaborative editing of documents, spreadsheets, presentations, and vector graphics directly in a browser, with strong compatibility for both the OpenDocument format and Microsoft Office file formats.$q$, $q$Native apps extend offline access across Android, ChromeOS, iOS, iPadOS, Linux, macOS, and Windows, and because it's self-hosted, organizations keep full control over where document data is stored, supporting GDPR and other data-residency requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Collabora Online Development Edition (CODE) is free and updated roughly monthly, suited to testing, personal use, or small teams, but not recommended for large-scale production due to its faster, less stable release cadence.$q$, $q$Commercial, production-ready editions are sold on an annual subscription, with reported starting rates around €3 per user per month for on-premise deployments up to about 99 users, and custom pricing for larger Enterprise deployments that add long-term support and signed security updates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('314b57b0-8a83-4a7f-9610-e611f8f2c94f', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Configurable cataloging$q$, $q$Highly customizable data models and metadata standards without requiring custom code for most configuration changes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Multi-format media support$q$, $q$Handles documents, images, audio, video, and 3D object records within the same system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Batch import and export$q$, $q$Bulk data and media import/export tools for migrating or updating large collections.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Public-facing publishing (Pawtucket2)$q$, $q$Companion application for making cataloged collections searchable and browsable online.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Role-based access control$q$, $q$User and role permissions for controlling who can view or edit specific records.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Open-source licensing$q$, $q$Released under GPLv3, free to download, modify, and self-host without licensing fees.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Highly configurable for diverse collection types (museum objects, archival documents, audio/video, 3D)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Long track record, in active use since 2003 by hundreds of institutions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Optional professional services (hosting, migration, development) available through the maintaining company$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Requires self-hosting a PHP/MySQL application, which demands in-house or contracted technical capacity$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$No fully managed, zero-setup SaaS option from the core project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Configuration complexity can be significant for institutions without prior systems experience$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Documentation and support are community/vendor-driven rather than a large commercial support organization$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Is CollectiveAccess free?$q$, $q$Yes. CollectiveAccess, including its Providence cataloging component, is free, open-source software released under the GPLv3 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Who maintains CollectiveAccess?$q$, $q$It's maintained by Whirl-i-Gig, a software and consulting company based in Brooklyn, New York, with contributions from the open-source community.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$What's the difference between Providence and Pawtucket2?$q$, $q$Providence is the back-end cataloging application institutions use to manage collection records; Pawtucket2 is the companion front-end for publishing those collections publicly online.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$What technology does CollectiveAccess run on?$q$, $q$It runs on a PHP and MySQL stack; current releases support PHP 8.2 and 8.3.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Who uses CollectiveAccess?$q$, $q$Hundreds of institutions, including national museums, local history consortia, and specialized archives, such as the Kress Digital Archive at the National Gallery of Art and Chicago Film Archives.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Museum object cataloging$q$, $q$A museum installs Providence to catalog its physical collection with detailed, standards-based metadata and manage digitized images of each object.$q$, $q$Museums and cultural heritage institutions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$Public archive with online browsing$q$, $q$An archive combines Providence for internal cataloging with Pawtucket2 to publish a searchable, browsable version of its collection to the public.$q$, $q$Archives, libraries, and research collections$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CollectiveAccess is free, open-source collections management software that began in 2003 to address the lack of affordable, non-commercial cataloging options for museums and archives. It is maintained by Whirl-i-Gig, a small development and consulting company based in Brooklyn, New York, with community contributions.$q$, $q$The suite has two parts: Providence, the configurable back-end cataloging system institutions use to describe and manage their holdings, and Pawtucket2, the companion front-end for publishing collections online for public browsing and search.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Providence supports a wide range of metadata standards and content types, including documents, images, audio, video, and 3D objects, with web-based cataloging, batch import/export, and customizable data models that don't require custom programming for most configuration.$q$, $q$It runs on a PHP/MySQL stack (current builds support PHP 8.2/8.3), is released under the GPLv3 open-source license, and is used by hundreds of institutions worldwide, from national museums to small local archives.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The software itself is entirely free to download, install, and use under the GPLv3 license, with no subscription fee. Institutions cover their own hosting and staff time, or optionally contract Whirl-i-Gig for custom development, data migration, hosting, or public-website services.$q$, $q$Because pricing for professional services is scoped per project rather than published as fixed tiers, there is no standard public price list beyond the software being free.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f7ad8964-3bed-4b24-a76a-71a5d1f01f13', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
