-- Enrichment marathon batch: CoConstruct, Coda (Superhuman Docs), Devin Desktop (formerly Codeium / Windsurf), Cognism, Cognito Forms, Colanode, Collabora Online, CollectiveAccess (Providence)

-- ── CoConstruct ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CoConstruct is construction project management software built for custom home builders and remodelers, now transitioning into Buildertrend following their 2021 merger.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$199/month (legacy plans; new customers are directed to Buildertrend)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Charlottesville, Virginia, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CoConstruct: Features, Pricing & Buildertrend Merger$q$, seo_title),
  seo_meta_description = COALESCE($q$CoConstruct is construction management software for custom home builders, now transitioning to Buildertrend. See pricing, features, and migration details.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CoConstruct is a construction project management platform built specifically for custom home builders and remodelers, founded in 2005 and headquartered in Charlottesville, Virginia. It grew to serve more than 100,000 building professionals, with a typical customer base of firms building 5 to 50 homes per year. Core functionality historically included scheduling, budgeting and job costing, selections management (letting homeowners choose finishes and fixtures within a budget), change order tracking, client and subcontractor communication tools, photo and document storage, and a client portal that gives homeowners visibility into their project's progress. CoConstruct integrated with QuickBooks and Xero for accounting sync and offered mobile apps so site managers could update schedules and log information from job sites. On February 24, 2021, Buildertrend, a competing construction management platform, acquired CoConstruct in a deal backed by Bain Capital Tech Opportunities and HGGC, creating what was described at the time as the market leader in construction management software for residential builders. For several years after the acquisition, CoConstruct continued operating as a distinct product alongside Buildertrend. As of 2026, the two companies are actively merging their platforms: CoConstruct's own migration materials describe a phased move of existing customers onto Buildertrend, with historical CoConstruct project data remaining accessible indefinitely, but new projects only being creatable within CoConstruct through March 31, 2027, after which all new work must be started directly in Buildertrend. Reporting from third-party reviewers indicates CoConstruct has not received meaningful product updates since the acquisition and that Buildertrend is not investing further in its independent development, positioning it as a legacy product being wound down in favor of a unified Buildertrend platform. Historical CoConstruct pricing was structured in tiers (commonly cited as roughly $199/month for a small-team Core tier, $399/month for a mid-size Essential tier, and $599/month for an unlimited-user Advanced tier), billed based on active job sites with client access rather than per generic seat, with discounts for annual billing. Because it is being sunset in favor of Buildertrend, CoConstruct is not a viable option for a builder evaluating new software today; it remains relevant primarily as context for existing customers going through migration, or for understanding the construction management software market's consolidation. Buildertrend itself continues to be sold to new customers and now carries forward CoConstruct's client-communication and selections-management concepts within its own interface. Anyone currently on CoConstruct should expect ongoing but non-expanding support, continued access to legacy data, and an eventual full transition to Buildertrend's tooling and pricing structure rather than CoConstruct's original plans.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'eb149729-5f83-425f-8d50-05c96971bdf3';

