-- ── Coda (Superhuman Docs) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Coda is an all-in-one docs, tables, and automation workspace, acquired by Grammarly in 2024 and rebranded to Superhuman Docs in July 2026.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $12/Doc Maker/month, $10 billed annually)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Coda (Superhuman Docs): Features, Pricing & Rebrand$q$, seo_title),
  seo_meta_description = COALESCE($q$Coda, now Superhuman Docs, blends documents, spreadsheets, and automation in one workspace. Compare its pricing, features, and 2026 Grammarly rebrand.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Coda is an all-in-one workspace that combines documents, spreadsheet-style tables, and app-like building blocks, originally founded in 2014 by Shishir Mehrotra along with Rehman Ali, Jean-Baptiste Coger, and Alex DeNeui, and headquartered in San Francisco. Coda's product model lets teams write free-form documents that also contain structured, relational tables, and layer in buttons, automations, and third-party integrations called Packs to turn a document into a lightweight application, positioning it as a hybrid between Google Docs, Airtable, and project management tools like Asana. On December 19, 2024, writing-assistant company Grammarly announced it was acquiring Coda, with Coda's CEO and co-founder Shishir Mehrotra becoming Grammarly's new CEO. In 2025, Grammarly separately acquired the AI email client Superhuman, founded by Rahul Vohra. On October 29, 2025, Grammarly announced a full company rebrand: the parent company itself became Superhuman, uniting Grammarly's writing assistant, Coda's workspace, and Superhuman's email client under one brand alongside a new AI assistant called Superhuman Go. As the final step of that transition, on July 8, 2026, Coda was renamed Superhuman Docs. According to Superhuman's own help documentation, existing Coda users keep all of their docs, tables, Packs, automations, and formulas working exactly as before under the new name, and the underlying product experience is unchanged aside from new AI capabilities built into documents and updated backend data infrastructure. Coda's pricing structure has continued largely unchanged through the rebrand: a Free plan caps shared docs at roughly 50 objects and 1,000 rows with basic collaboration; Pro costs $12 per Doc Maker per month ($10 if billed annually) and adds cross-doc tables and automations; Team costs $36 per Doc Maker per month ($30 annually) and adds administrative controls; and Enterprise is custom-priced with SSO/SCIM, one-year audit log retention, SOC 2 Type II and ISO 27001/27017/27018 compliance, dedicated support, and a large monthly AI credit allowance per Doc Maker. A distinguishing part of Coda's billing model, which reportedly carries over to Superhuman Docs, is that only "Doc Makers" (people who create or manage docs) are billed; "Editors" who only fill in or edit existing content can collaborate at no charge. Coda/Superhuman Docs is available as a web app with native desktop apps for Mac and Windows and mobile apps for iOS and Android, and it exposes an API and a Packs SDK for building custom integrations. It's used by teams for internal wikis, product and project trackers, CRMs, OKR tracking, and other lightweight internal tools that would otherwise require separate spreadsheet and database software. Anyone researching or comparing this tool today should treat "Coda" and "Superhuman Docs" as the same underlying product under different names, with Superhuman Docs being the current, accurate branding as of mid-2026.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '68d2cc39-83c1-4877-8a8c-2057a904b538';

