-- ── Devin Desktop (formerly Codeium / Windsurf) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Devin Desktop is an AI-powered code editor, originally launched as Codeium in 2021, renamed Windsurf in 2024, and rebranded again to Devin Desktop by Cognition AI in June 2026.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $20/month)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Devin Desktop (Codeium/Windsurf): Pricing & Rebrand$q$, seo_title),
  seo_meta_description = COALESCE($q$Devin Desktop, formerly Codeium and then Windsurf, is an AI coding editor now under Cognition AI. See its 2026 rebrand, pricing, and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$This tool has gone through three names in its history. It began in 2021 as Exafunction, a GPU virtualization startup founded by Varun Mohan and Douglas Chen and based in Mountain View, California. In 2022 the company pivoted to AI-assisted coding and rebranded as Codeium, an AI autocomplete and chat plugin for editors like VS Code and JetBrains IDEs, offering free-forever autocomplete as its core hook alongside paid tiers for teams. In late 2024, the company rebranded again to Windsurf and shipped Windsurf Editor, a full standalone AI-native IDE (a fork of VS Code) built around an agentic coding mode called Cascade, moving the product from a plugin-only tool to a complete development environment; the Codeium name was retained for the underlying plugin and account/authentication layer. Windsurf became one of the most closely watched AI coding startups of 2025, including a widely reported near-acquisition attempt by Google that instead resulted in Google licensing Windsurf's technology and hiring some of its leadership. In December 2025, Cognition AI, the developer of the autonomous coding agent Devin (founded in August 2023 by Scott Wu, Steven Hao, and Walden Yan, headquartered in San Francisco), acquired Windsurf for a reported price around $250 million. On June 2, 2026, Cognition rebranded Windsurf to Devin Desktop, folding it fully under the Devin product family. According to Cognition's documentation, this was a like-for-like rename delivered as an over-the-air update to existing installs: accounts, plans, extensions, keybindings, and MCP connections carried over automatically, and pricing was unchanged through the transition. Functionally, Devin Desktop replaced the home screen with an Agent Command Center, a Kanban-style board for managing local and cloud coding agents, and introduced Devin Local, a faster, Rust-based successor to Cascade (which reached end of life on July 1, 2026) capable of spawning parallel subagents. The editor also added support for the open Agent Client Protocol (ACP), letting third-party agents such as Codex, Claude Agent, and Gemini CLI run inside the same interface rather than being locked to one vendor's agent. As of mid-2026, pricing is Free (unlimited basic autocomplete, chat, and limited agent usage across 70+ programming languages), Pro at $20/month, Max at $200/month for power users, Teams at $80/month plus $40 per seat, and custom Enterprise pricing, including legacy Windsurf Enterprise contracts. Plugins remain available for VS Code, JetBrains IDEs, Neovim, Visual Studio, and other editors in addition to the full standalone desktop app, on macOS and Windows. Anyone researching this product under the name "Codeium" should understand that the current, accurate name as of mid-2026 is Devin Desktop, developed by Cognition AI.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aa297366-5cbc-4dc6-bc99-46ced5726132';

