-- ── Cognism ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cognism is a B2B sales intelligence platform providing GDPR-compliant, phone-verified contact and company data for outbound sales teams, especially in EMEA.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$500+ employees$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cognism: B2B Sales Intelligence Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Cognism provides GDPR-compliant, phone-verified B2B contact data for sales teams. See how it compares on pricing, coverage, and CRM integrations.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cognism is a B2B sales intelligence and contact data platform founded in 2015 (formally incorporated in 2017) by James Isilay, a former algorithmic trader, and Stjepan Buljat, a software architecture specialist. The company is headquartered in London, with additional offices in New York, Skopje, and Zadar, and reported around $83 million in annual recurring revenue with roughly 6,400 customers as of 2024, growing toward the $100 million ARR range by 2025. Cognism's core product delivers verified contact information (email addresses and, notably, human-verified mobile phone numbers) plus firmographic and intent data to power outbound sales prospecting, primarily for teams targeting Europe, the Middle East, and Africa (EMEA), where the company positions itself as having stronger coverage than US-centric competitors like ZoomInfo. Its Diamond Data tier uses human researchers who manually call and confirm mobile numbers rather than relying purely on algorithmic prediction, claiming around 87% accuracy, and the company maintains a database of more than 10 million phone-verified contacts. Cognism emphasizes regulatory compliance as a core differentiator: it is GDPR- and CCPA-compliant, holds ISO 27001 and SOC 2 Type II certifications, is registered with the UK Information Commissioner's Office, is registered as a data broker under CCPA in the United States, and cross-references contacts against Do Not Call and Telephone Preference Service lists across roughly 15 territories. The platform integrates with major CRM and sales engagement tools, including Salesforce, HubSpot, Outreach, Salesloft, Microsoft Dynamics 365, Bullhorn, and Pipedrive, with native connectors that carry compliance metadata along with the synced contact data, plus a Chrome extension that surfaces verified contact details while browsing LinkedIn or a target company's website. Cognism does not publish pricing publicly; prospective customers go through a sales demo and negotiation process. Third-party sources tracking real deal data (such as Vendr) report that actual Cognism contracts commonly range from roughly $1,500 to $25,000 per year depending on tier, team size, and negotiation, with named tiers historically including a Platinum/Grow tier starting around $1,500 per user per year and a Diamond/Elevate tier starting around $2,500 per user per year, on top of platform fees that can run $15,000 to $25,000 annually before per-seat costs. Because none of these figures come from Cognism's own published pricing page, they should be treated as directional estimates rather than confirmed rates. Cognism is best suited for outbound sales, SDR, and RevOps teams that need compliant, mobile-verified contact data for cold calling and email outreach, particularly those selling into European markets where data protection rules are stricter than in the US.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '48c4e035-ee4a-4d7c-9e7a-7d9f3a3f6d4e';

