-- ── Cognito Forms ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cognito Forms is a drag-and-drop online form builder with conditional logic, payment collection, and workflow automation, offering a free plan and paid tiers.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $19.20/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$47 employees$q$, company_size),
  headquarters = COALESCE($q$Columbia, South Carolina, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cognito Forms: Pricing, Features & Free Plan Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Cognito Forms is a no-code form builder with conditional logic and payments. Compare its Free, Pro, Team, and Enterprise plans and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cognito Forms is an online form-building platform founded on December 10, 2013 by Alain Meier and Jamie Thomas, following several years of custom web development work for clients in Columbia, South Carolina, where the company remains headquartered. It grew out of the founders repeatedly building bespoke data-collection tools for clients and deciding to turn that into a single self-serve platform; the company reports around 47 employees as of 2026. Cognito Forms provides a drag-and-drop, no-code form builder that lets users create and embed custom forms with conditional logic (showing or hiding fields based on prior answers), automated cost calculations, date comparisons, electronic signature capture, and file uploads. It supports accepting payments directly through forms via Stripe, PayPal, or Square, making it commonly used for registrations, applications, and order forms that need to collect money as part of the submission. Data-handling features include entry sharing, data merging, confirmation email management, folder-level permissions, and HIPAA-compliant configurations on higher plans, along with data encryption. It integrates with other software through Zapier, Microsoft Power Automate, and JSON webhooks, letting form submissions trigger workflows in other systems without custom code. Pricing follows a four-tier freemium model. The Individual plan is free forever, with no credit card required, and includes one user, up to 100 form entries per month, 100 MB of storage, and unlimited forms with payment acceptance. The Pro plan costs $24/month billed monthly or $19.20/month billed annually, covering 2 users, 2,000 entries per month, 1 GB of storage, electronic signatures, save-and-resume functionality, and the ability to remove Cognito Forms branding. The Team plan, described as the best-value tier, costs $49/month monthly or $39.20/month annually, covering 5 users plus 5 included guest accounts, 10,000 entries per month, 10 GB of storage, a client portal, workflow and approval features, and data lookups. The Enterprise plan costs $174/month monthly or $129.60/month annually, covering 20 users plus 20 guests, unlimited entries, 100 GB of storage, HIPAA compliance, folder permissions, and single sign-on. All paid plans build on the free tier's unlimited-forms and payment-acceptance foundation while raising entry volume, storage, and collaboration limits. Cognito Forms is best suited for small businesses, nonprofits, schools, and healthcare-adjacent organizations that need more configurable logic and payment handling than a basic contact-form tool provides, without requiring a developer to build custom logic.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8d0cb449-bb08-4c54-9e30-c13e9e4fee0c';

