-- ── Colanode ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Colanode is an open-source, local-first collaboration workspace combining Slack-style chat and Notion-style pages, databases, and files, self-hostable by default.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted or free beta cloud)$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Colanode: Open-Source Slack & Notion Alternative$q$, seo_title),
  seo_meta_description = COALESCE($q$Colanode is an open-source, local-first workspace combining chat, docs, and databases. Self-host it or use the free beta cloud. See features and setup.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Colanode is an open-source, local-first collaboration workspace created in 2024 (the GitHub repository dates to July 29, 2024) as a self-hostable alternative that combines functionality similar to Slack and Notion in one tool. It was introduced publicly on Hacker News as a "Show HN" project and has since grown to over 5,000 GitHub stars across more than 1,000 commits and 40-plus releases, with the codebase released under the Apache 2.0 open-source license and written primarily in TypeScript. The product bundles four main capabilities: real-time chat for team messaging, rich-text pages for documents and wikis, customizable databases with multiple views (table, kanban, and calendar) for structured data, and file management for storing and sharing files within a workspace. Its defining architectural feature is a local-first design: every change is written to a local SQLite database on the user's device first, and a background sync process pushes changes to the server, so the app remains usable offline and reads happen instantly from local storage rather than waiting on a network round trip. Real-time collaborative editing (for example, multiple people editing the same page simultaneously) is powered by Conflict-free Replicated Data Types (CRDTs) via the Yjs library, which merges concurrent edits without conflicts. Colanode ships as both a web app (accessible at app.colanode.com) and a desktop application built with Electron, and it can be self-hosted for full control over data. Self-hosting requires PostgreSQL with the pgvector extension, Redis (or a Valkey-compatible alternative), and a file storage backend, which defaults to the local filesystem but also supports S3-compatible storage, Google Cloud Storage, or Azure Blob Storage; documentation describes both a simple single-server setup and a more complex, production-grade distributed deployment. For users who don't want to run their own infrastructure, Colanode also offers hosted cloud servers in the EU and US regions, currently in beta and free to use while the company works out a longer-term monetization strategy; as of mid-2026 there is no finalized public pricing for a paid cloud tier. Because it is fully open source and self-hostable, Colanode is positioned for privacy- and data-ownership-conscious teams, technical organizations that already run their own infrastructure, and individuals or small teams who want a Notion/Slack-style tool without a recurring SaaS subscription or third-party data hosting. It's best evaluated as a young, actively developed project rather than a mature enterprise product: as of 2026 its cloud monetization plan is still being finalized, and adopters should expect a self-hosted or beta-cloud experience rather than a polished managed-service offering with SLAs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
