-- ── Collabora Online ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Collabora Online is an open-source, self-hostable office suite for real-time collaborative editing of documents, spreadsheets, and presentations in a browser.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (CODE edition); Business tier from roughly €3/user/month$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Cambridge, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$Collabora Online: Open-Source Office Suite Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Collabora Online is a self-hosted, open-source alternative to Google Workspace and Microsoft 365. See its features, editions, and pricing tiers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Collabora Online is a browser-based, real-time collaborative office suite built on LibreOffice Online technology and developed by Collabora, a UK open-source consulting company founded in 2005 by Robert McQueen, Philippe Kalaf, and Robert Taylor and headquartered in Cambridge, with an additional office in Montreal. Collabora is one of the largest corporate contributors to the LibreOffice codebase, and Collabora Online packages that engine into a web-based suite covering Writer (word processing), Calc (spreadsheets), Impress (presentations), and Draw (vector graphics), positioned as an open-source alternative to Google Workspace and Microsoft 365. Unlike those proprietary cloud suites, Collabora Online is designed to be self-hosted (or hosted by a third party) rather than run exclusively as Collabora's own SaaS product, and it does not function as a standalone service; it integrates into an existing file-storage platform such as Nextcloud, ownCloud, EGroupware, or Pydio, which supplies the file storage and user management while Collabora Online provides the in-browser editing layer. It supports the OpenDocument format natively and offers strong compatibility with Microsoft Office formats (.docx, .xlsx, .pptx), enabling real-time multi-user editing directly in a browser. For offline and native use, Collabora also ships apps for Android, ChromeOS, iOS, iPadOS, Linux, macOS, and Windows. The product is distributed in two main tracks. Collabora Online Development Edition (CODE) is completely free, released roughly monthly, and recommended for testing, personal use, or small teams, but explicitly not recommended for large-scale production deployments due to its faster-moving, less battle-tested release cycle; it's the version most commonly bundled for free with self-hosted Nextcloud installs. Commercial, production-grade editions are sold through Collabora under subscription pricing, generally billed annually, with reported starting rates around €3 per user per month for on-premise deployments of up to about 99 users, and custom Enterprise-scale pricing for larger organizations; these paid tiers add long-term support, signed security updates, and higher stability and scalability guarantees. Collabora is also GDPR compliant by design, since self-hosting keeps data within an organization's own infrastructure rather than a third-party cloud. Because self-hosted deployments eliminate recurring per-user SaaS fees, Collabora Online can be more cost-effective than Microsoft 365 or Google Workspace at scale for organizations with the technical capacity to run and maintain the infrastructure, particularly public sector bodies, privacy-focused organizations, and companies already running Nextcloud or ownCloud. It is less suited to organizations that want a fully managed, zero-maintenance cloud office suite without any self-hosting involvement.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '314b57b0-8a83-4a7f-9610-e611f8f2c94f';

