-- ── CollectiveAccess (Providence) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Providence is the free, open-source cataloging engine of CollectiveAccess, used by museums, archives, and libraries to manage and describe digital and physical collections.$q$, short_description),
  pricing_model = COALESCE($q$Free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Brooklyn, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CollectiveAccess Providence: Free Collections Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Providence is CollectiveAccess's open-source cataloging software for museums and archives. See its features, licensing, and who maintains it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CollectiveAccess is free, open-source software for cataloging and publishing museum, archival, and library collections, with the project originating in 2003 in response to a lack of affordable, non-commercial collections management options. It is maintained by Whirl-i-Gig, a small software and consulting company based in Brooklyn, New York, with ongoing contributions from the open-source community. The suite consists of two applications: Providence, the back-end cataloging component, and Pawtucket2, the front-end public-facing web publishing component used to make collections browsable and searchable online. Providence is the core system institutions install and configure to catalog their holdings; it is highly configurable and can support a wide range of metadata standards and content types, including documents, images, audio, video, and 3D objects, without requiring custom programming for most configuration changes. Its feature set includes web-based cataloging forms, batch import and export of records and media, customizable data models, user and role-based access control, and reporting tools. The current major release line is CollectiveAccess 2.0, and the software runs on a PHP/MySQL stack, with recent versions supporting PHP 8.2 and 8.3. It is released under the GNU General Public License version 3 (GPLv3), meaning it can be freely downloaded, installed, modified, and shared without licensing fees. CollectiveAccess is used by hundreds of institutions worldwide, spanning national museums, local history consortia, specialized archives, and catalogues raisonnés, including notable implementations such as the Kress Digital Archive at the National Gallery of Art, Chicago Film Archives, and the Samek Art Museum at Bucknell University. Because it is entirely free and open source, there is no vendor subscription fee for the software itself; institutions instead invest in their own hosting and staff time to install, configure, and maintain it, or optionally pay Whirl-i-Gig for professional services such as custom development, data migration, digital preservation consulting, hosting, and public-facing website design and development. Documentation, community forums, live chat support, and a public demonstration sandbox are available to help institutions evaluate and configure the system before committing resources. CollectiveAccess/Providence is best suited for museums, archives, libraries, and research collections that need a flexible, standards-based cataloging system and have some in-house or contracted technical capacity to install and maintain a self-hosted PHP/MySQL application, rather than organizations looking for a fully managed, no-setup SaaS product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f7ad8964-3bed-4b24-a76a-71a5d1f01f13';

